import { apiRequest, buildApiUrl } from "./apiClient";
import { Workout } from "../types/api.types";

export const workoutsService = {
  async getWorkoutById(workoutId: string, token: string): Promise<Workout> {
    return apiRequest<Workout>(buildApiUrl(`/workouts/${workoutId}`), {
      method: "GET",
      headers: { Authorization: `Bearer ${token}` },
    });
  },

  async getCourseWorkouts(courseId: string, token: string): Promise<any[]> {
    return apiRequest<any[]>(buildApiUrl(`/courses/${courseId}/workouts`), {
      method: "GET",
      headers: token ? { Authorization: `Bearer ${token}` } : undefined,
    });
  },

  async getWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string
  ): Promise<{
    workoutId: string;
    workoutCompleted: boolean;
    progressData: number[];
  }> {
    return apiRequest<any>(
      buildApiUrl(`/users/me/progress?courseId=${courseId}&workoutId=${workoutId}`),
      {
        method: "GET",
        headers: { Authorization: `Bearer ${token}` },
      }
    );
  },

  async saveWorkoutProgress(
    courseId: string,
    workoutId: string,
    progressData: number[],
    token: string
  ): Promise<{ message: string }> {
    return apiRequest<{ message: string }>(
      buildApiUrl(`/courses/${courseId}/workouts/${workoutId}`),
      {
        method: "PATCH",
        headers: { Authorization: `Bearer ${token}` },
        body: JSON.stringify({ progressData }),
      }
    );
  },

  async resetWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string
  ): Promise<{ message: string }> {
    return apiRequest<{ message: string }>(
      buildApiUrl(`/courses/${courseId}/workouts/${workoutId}/reset`),
      {
        method: "PATCH",
        headers: { Authorization: `Bearer ${token}` },
      }
    );
  },
};
